"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[2022],{8822(t,e,a){a.r(e),a.d(e,{comp:()=>n,data:()=>r});var d=a(641);const i={},n=(0,a(6262).A)(i,[["render",function(t,e){return(0,d.uX)(),(0,d.CE)("div",null,[...e[0]||(e[0]=[(0,d.Fv)('<h1 id="withdrawal" tabindex="-1"><a class="header-anchor" href="#withdrawal"><span>Withdrawal</span></a></h1><p><strong><code>/my-account/wkwc_withdrawal/</code></strong> — customers request wallet payout to their bank, PayPal, or custom payment method.</p><p><img src="/auctions-for-woocommerce/images/screenshots/front-wallet-balance.png" alt="Wallet panel — balance card and the area customers use to request a withdrawal payout"></p><h2 id="prerequisites" tabindex="-1"><a class="header-anchor" href="#prerequisites"><span>Prerequisites</span></a></h2><table><thead><tr><th>Requirement</th><th>Setting</th></tr></thead><tbody><tr><td>Withdrawal feature enabled</td><td>Master switch in <strong>Settings → Payments → Wallet</strong></td></tr><tr><td>Customer has positive wallet balance</td><td>(live)</td></tr><tr><td>Customer has saved at least one payment method</td><td>(filled-in below)</td></tr></tbody></table><h2 id="page-layout" tabindex="-1"><a class="header-anchor" href="#page-layout"><span>Page layout</span></a></h2><p>Two sections:</p><ol><li><strong>Saved Payment Methods</strong> — accounts you&#39;ve added (bank / PayPal / custom)</li><li><strong>Withdrawal Request</strong> — form to request a new payout</li></ol><p>Plus a <strong>Request History</strong> table showing past withdrawals and their statuses.</p><h2 id="adding-a-payment-method" tabindex="-1"><a class="header-anchor" href="#adding-a-payment-method"><span>Adding a payment method</span></a></h2><p>Click <strong>Add Withdrawal Method</strong> at the top right.</p><p>A modal asks for:</p><table><thead><tr><th>Method</th><th>Required fields</th></tr></thead><tbody><tr><td><strong>Bank transfer</strong></td><td>Account holder name, bank name, account number, IFSC / SWIFT, branch</td></tr><tr><td><strong>PayPal</strong></td><td>PayPal email</td></tr><tr><td><strong>Custom</strong></td><td>Free-form fields configured by admin</td></tr></tbody></table><div class="hint-container warning"><p class="hint-container-title">These details aren&#39;t validated automatically</p><p>The plugin doesn&#39;t verify your bank account exists. Admin manually reviews before approving payouts.</p></div><p>Saved methods appear in a list; you can edit or delete them. They&#39;re stored as encrypted user-meta.</p><h2 id="requesting-a-withdrawal" tabindex="-1"><a class="header-anchor" href="#requesting-a-withdrawal"><span>Requesting a withdrawal</span></a></h2><ol><li><strong>Select a payment method</strong> (radio button)</li><li><strong>Enter amount</strong> — must be ≥ the configured minimum</li><li><strong>Add note</strong> (optional — context for admin)</li><li>Click <strong>Request Withdrawal</strong></li></ol><p>The request is created with status <code>pending</code>. Your wallet balance is <strong>not</strong> debited until admin approves it (so the funds remain spendable on auctions until then).</p><h2 id="limits" tabindex="-1"><a class="header-anchor" href="#limits"><span>Limits</span></a></h2><table><thead><tr><th>Limit</th><th>Default</th><th>Configurable in</th></tr></thead><tbody><tr><td>Minimum withdrawal</td><td>100</td><td>Wallet settings</td></tr><tr><td>Maximum withdrawal per request</td><td>(admin-configurable)</td><td>Wallet settings</td></tr><tr><td>Daily withdrawal cap</td><td>(off by default)</td><td>Wallet settings</td></tr><tr><td>Withdrawal fee</td><td>0</td><td>Wallet settings</td></tr></tbody></table><p>If the limit is hit, the form shows an inline error before submission.</p><h2 id="request-statuses" tabindex="-1"><a class="header-anchor" href="#request-statuses"><span>Request statuses</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">pending   →  approved  →  paid</span>\n<span class="line">   ↓</span>\n<span class="line">rejected</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th>Status</th><th>What it means</th></tr></thead><tbody><tr><td><strong>Pending</strong></td><td>Submitted, waiting for admin review</td></tr><tr><td><strong>Approved</strong></td><td>Admin approved; payout in progress</td></tr><tr><td><strong>Paid</strong></td><td>Admin confirms payout completed; wallet balance debited</td></tr><tr><td><strong>Rejected</strong></td><td>Admin rejected; reason shown; wallet balance untouched</td></tr></tbody></table><h2 id="request-history" tabindex="-1"><a class="header-anchor" href="#request-history"><span>Request History</span></a></h2><p>The bottom of the page lists every withdrawal you&#39;ve made:</p><table><thead><tr><th>Column</th><th>Source</th></tr></thead><tbody><tr><td>Request ID</td><td>unique reference</td></tr><tr><td>Method</td><td>bank / PayPal / custom</td></tr><tr><td>Amount</td><td>requested amount</td></tr><tr><td>Fee</td><td>deducted fee (if any)</td></tr><tr><td>Net</td><td>amount you actually receive</td></tr><tr><td>Status</td><td>per above</td></tr><tr><td>Submitted</td><td>timestamp</td></tr><tr><td>Updated</td><td>timestamp of last status change</td></tr><tr><td>Actions</td><td>View / Edit (pending only) / Delete (pending only)</td></tr></tbody></table><p>Click <strong>View</strong> for full details, including any admin rejection reason.</p><h2 id="editing-cancelling-a-pending-request" tabindex="-1"><a class="header-anchor" href="#editing-cancelling-a-pending-request"><span>Editing / cancelling a pending request</span></a></h2><p>While status is <code>pending</code>, you can:</p><ul><li><strong>Edit</strong> — change the amount, method, or note</li><li><strong>Delete</strong> — cancel the request entirely</li></ul><p>Once <code>approved</code>, no edits are allowed (admin owns the payout from there).</p><h2 id="notifications" tabindex="-1"><a class="header-anchor" href="#notifications"><span>Notifications</span></a></h2><table><thead><tr><th>Trigger</th><th>Email</th></tr></thead><tbody><tr><td>Request submitted</td><td>&quot;Withdrawal request received&quot;</td></tr><tr><td>Request approved</td><td>&quot;Withdrawal approved — payout in progress&quot;</td></tr><tr><td>Request paid</td><td>&quot;Withdrawal sent — funds dispatched&quot;</td></tr><tr><td>Request rejected</td><td>&quot;Withdrawal could not be processed&quot; with reason</td></tr></tbody></table><p>Templates editable in <strong>WooCommerce → Settings → Emails</strong>.</p><h2 id="admin-side-workflow" tabindex="-1"><a class="header-anchor" href="#admin-side-workflow"><span>Admin-side workflow</span></a></h2><p>What happens after you submit:</p><ol><li>Admin sees your request in <a href="/admin-wallet.html#withdrawal-queue" target="_blank" rel="noopener noreferrer">Wallet → Withdrawal queue</a></li><li>Admin reviews your saved bank / PayPal details</li><li>Admin clicks <strong>Approve</strong> → executes payout (Stripe Connect, PayPal Payouts, manual bank transfer — depends on admin&#39;s setup)</li><li>Admin clicks <strong>Mark Paid</strong> when payout completes</li><li>Your wallet balance is debited</li><li>You receive the &quot;Withdrawal sent&quot; email</li></ol><p>Approval timing: typically 1–3 business days. Configurable SLA tracked on the admin side.</p><h2 id="why-my-withdrawal-might-be-rejected" tabindex="-1"><a class="header-anchor" href="#why-my-withdrawal-might-be-rejected"><span>Why my withdrawal might be rejected</span></a></h2><table><thead><tr><th>Reason</th><th>Fix</th></tr></thead><tbody><tr><td>Bank details incomplete</td><td>Edit saved method, add missing fields</td></tr><tr><td>Account name mismatch</td><td>Account holder name must match your registered name</td></tr><tr><td>Below minimum threshold</td><td>Wait until balance is higher</td></tr><tr><td>Recent disputes / chargebacks</td><td>Resolve disputes before re-requesting</td></tr><tr><td>KYC not completed (if required)</td><td>Submit KYC documents in <strong>My Account → Account details</strong></td></tr><tr><td>Suspicious activity flagged</td><td>Contact support</td></tr></tbody></table><h2 id="security" tabindex="-1"><a class="header-anchor" href="#security"><span>Security</span></a></h2><ul><li>All withdrawal requests are logged in the <a href="/admin-audit-log.html" target="_blank" rel="noopener noreferrer">Audit Log</a></li><li>Bank details are encrypted at rest in user-meta</li><li>Admin actions on your withdrawal are logged with timestamp + admin user ID</li><li>The plugin does <strong>not</strong> initiate bank transfers automatically — admin manually executes each payout</li></ul><h2 id="common-questions" tabindex="-1"><a class="header-anchor" href="#common-questions"><span>Common questions</span></a></h2><p><strong>&quot;How long until I get paid?&quot;</strong></p><p>After admin approval, payout depends on the method:</p><table><thead><tr><th>Method</th><th>Typical</th></tr></thead><tbody><tr><td>Bank transfer</td><td>1–5 business days</td></tr><tr><td>PayPal</td><td>Same day or next business day</td></tr><tr><td>Custom</td><td>Depends on admin&#39;s payout system</td></tr></tbody></table><p><strong>&quot;Can I cancel a pending request?&quot;</strong></p><p>Yes — click <strong>Delete</strong> on the row. Only works while status is <code>pending</code>.</p><p><strong>&quot;Can I withdraw my full balance?&quot;</strong></p><p>Subject to minimums and any daily cap. If your balance exceeds the daily cap, split into multiple requests over consecutive days.</p><p><strong>&quot;Why can&#39;t I see this page?&quot;</strong></p><p>Withdrawal might be disabled in <strong>Settings → Payments → Wallet → Withdrawal</strong>. Contact support.</p>',53)])])}]]),r=JSON.parse('{"path":"/customer-withdrawal.html","title":"Withdrawal","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"Prerequisites","slug":"prerequisites","link":"#prerequisites","children":[]},{"level":2,"title":"Page layout","slug":"page-layout","link":"#page-layout","children":[]},{"level":2,"title":"Adding a payment method","slug":"adding-a-payment-method","link":"#adding-a-payment-method","children":[]},{"level":2,"title":"Requesting a withdrawal","slug":"requesting-a-withdrawal","link":"#requesting-a-withdrawal","children":[]},{"level":2,"title":"Limits","slug":"limits","link":"#limits","children":[]},{"level":2,"title":"Request statuses","slug":"request-statuses","link":"#request-statuses","children":[]},{"level":2,"title":"Request History","slug":"request-history","link":"#request-history","children":[]},{"level":2,"title":"Editing / cancelling a pending request","slug":"editing-cancelling-a-pending-request","link":"#editing-cancelling-a-pending-request","children":[]},{"level":2,"title":"Notifications","slug":"notifications","link":"#notifications","children":[]},{"level":2,"title":"Admin-side workflow","slug":"admin-side-workflow","link":"#admin-side-workflow","children":[]},{"level":2,"title":"Why my withdrawal might be rejected","slug":"why-my-withdrawal-might-be-rejected","link":"#why-my-withdrawal-might-be-rejected","children":[]},{"level":2,"title":"Security","slug":"security","link":"#security","children":[]},{"level":2,"title":"Common questions","slug":"common-questions","link":"#common-questions","children":[]}],"git":{},"filePathRelative":"customer-withdrawal.md"}')}}]);